6	//! GPU Debug and Profiling Intrinsics
7	//!
8	//! This module provides intrinsics for debugging and profiling GPU kernels:
9	//!
10	//! | Function           | Description                   | CUDA C++ Equivalent |
11	//! |--------------------|-------------------------------|---------------------|
12	//! | [`clock()`]        | Read 32-bit GPU clock counter | `clock()`           |
13	//! | [`clock64()`]      | Read 64-bit GPU clock counter | `clock64()`         |
14	//! | [`globaltimer()`]  | Read GPU global timer         | `%globaltimer`      |
15	//! | [`trap()`]         | Abort kernel execution        | `__trap()`          |
16	//! | [`breakpoint()`]   | Insert cuda-gdb breakpoint    | `__brkpt()`         |
17	//! | [`prof_trigger()`] | Signal NVIDIA profiler        | `__prof_trigger(N)` |
18	//!
19	//! # Example: Micro-benchmarking
20	//!
21	//! ```rust,ignore
22	//! use cuda_device::debug;
23	//!
24	//! let start = debug::clock64();
25	//! // ... computation to measure ...
26	//! let end = debug::clock64();
27	//! let cycles = end - start;
28	//! ```
29	//!
30	//! # Example: Runtime Assertion
31	//!
32	//! ```rust,ignore
33	//! use cuda_device::debug;
34	//!
35	//! if value < 0 {
36	//!     debug::trap();  // Kernel aborts
37	//! }
38	//! ```
39	
40	// =============================================================================
41	// Clock/Timing Intrinsics
42	// =============================================================================
43	
44	/// Read the GPU clock counter (32-bit).
45	///
46	/// Returns the current value of a per-SM clock counter. Useful for micro-benchmarking
47	/// kernel code by measuring elapsed cycles between operations.
48	///
49	/// # Returns
50	///
51	/// A 32-bit clock cycle count. Note that this wraps around relatively quickly
52	/// (~4 billion cycles). For longer measurements, use [`clock64()`].
53	///
54	/// # Example
55	///
56	/// ```rust,ignore
57	/// use cuda_device::debug;
58	///
59	/// let start = debug::clock();
60	/// // ... some computation ...
61	/// let end = debug::clock();
62	/// let cycles = end.wrapping_sub(start);
63	/// ```
64	///
65	/// # Notes
66	///
67	/// - Clock frequency varies by GPU and power state
68	/// - Different SMs may have slightly different clock values
69	/// - Use for relative timing within a kernel, not absolute time
70	#[inline(never)]
71	pub fn clock() -> u32 {
72	    // Lowered to: call i32 @llvm.nvvm.read.ptx.sreg.clock()
73	    unreachable!("clock called outside CUDA kernel context")
74	}
75	
76	/// Read the GPU clock counter (64-bit).
77	///
78	/// Returns the current value of a per-SM clock counter as a 64-bit value.
79	/// Preferred over [`clock()`] for measurements that might exceed 32-bit range.
80	///
81	/// # Returns
82	///
83	/// A 64-bit clock cycle count that won't wrap around for practical measurements.
84	///
85	/// # Example
86	///
87	/// ```rust,ignore
88	/// use cuda_device::debug;
89	///
90	/// let start = debug::clock64();
91	/// // ... some computation ...
92	/// let end = debug::clock64();
93	/// let cycles = end - start;  // No wrapping concerns
94	/// ```
95	///
96	/// # Notes
97	///
98	/// - Clock frequency varies by GPU and power state
99	/// - Different SMs may have slightly different clock values
100	/// - Use for relative timing within a kernel, not absolute time
101	#[inline(never)]
102	pub fn clock64() -> u64 {
103	    // Lowered to: call i64 @llvm.nvvm.read.ptx.sreg.clock64()
104	    unreachable!("clock64 called outside CUDA kernel context")
105	}
106	
107	/// Read the GPU global timer.
108	///
109	/// Returns a 64-bit timer value from PTX `%globaltimer`. Unlike [`clock64()`],
110	/// this is a global timer source, so it is preferable when measuring interactions
111	/// that may span multiple SMs.
112	///
113	/// # Example
114	///
115	/// ```rust,no_run
116	/// use cuda_device::debug;
117	///
118	/// let start = debug::globaltimer();
119	/// // ... operation to measure ...
120	/// let end = debug::globaltimer();
121	/// let ticks = end.wrapping_sub(start);
122	/// ```
123	#[inline(never)]
124	pub fn globaltimer() -> u64 {
125	    // Lowered to: call i64 @llvm.nvvm.read.ptx.sreg.globaltimer()
126	    unreachable!("globaltimer called outside CUDA kernel context")
127	}
128	
129	// =============================================================================
130	// Trap/Abort Intrinsics
131	// =============================================================================
132	
133	/// Abort kernel execution immediately.
134	///
135	/// This is equivalent to `__trap()` in CUDA C/C++. When any thread executes
136	/// `trap()`, the kernel is terminated and an error is reported to the host.
137	///
138	/// # Use Cases
139	///
140	/// - Runtime error checking (like `assert` but unconditional)
141	/// - Detecting invalid states that should never occur
142	/// - Debugging to stop execution at a specific point
143	///
144	/// # Example
145	///
146	/// ```rust,ignore
147	/// use cuda_device::debug;
148	///
149	/// if invalid_condition {
150	///     debug::trap();  // Kernel dies here
151	/// }
152	/// ```
153	///
154	/// # Notes
155	///
156	/// - The kernel terminates with an error status
157	/// - No error message is provided (use `gpu_assert!` for messages)
158	/// - Host will see a CUDA error when synchronizing
159	#[inline(never)]
160	pub fn trap() -> ! {
161	    // Lowered to: call void @llvm.nvvm.trap()
162	    unreachable!("trap called outside CUDA kernel context")
163	}
164	
165	// =============================================================================
166	// Debugging Intrinsics
167	// =============================================================================
168	
169	/// Insert a breakpoint for cuda-gdb.
170	///
171	/// When debugging with cuda-gdb, execution will stop at this point.
172	/// This is equivalent to `__brkpt()` in CUDA C/C++.
173	///
174	/// # Example
175	///
176	/// ```rust,ignore
177	/// use cuda_device::debug;
178	///
179	/// // Only break on thread 0 to avoid overwhelming the debugger
180	/// if thread::index_1d().get() == 0 {
181	///     debug::breakpoint();
182	/// }
183	/// ```
184	///
185	/// # Notes
186	///
187	/// - Only effective when running under cuda-gdb
188	/// - Without cuda-gdb, this is typically a no-op or trap
189	/// - Be careful about placing breakpoints in divergent code
190	#[inline(never)]
191	pub fn breakpoint() {
192	    // Lowered to: call void @llvm.nvvm.brkpt() or inline PTX "brkpt;"
193	    unreachable!("breakpoint called outside CUDA kernel context")
194	}
195	
196	/// Signal the NVIDIA profiler at a specific point.
197	///
198	/// Triggers a profiler event that can be viewed in Nsight Systems or
199	/// Nsight Compute. The counter `N` identifies the trigger point.
200	///
201	/// This is equivalent to `__prof_trigger(N)` in CUDA C/C++.
202	///
203	/// # Type Parameters
204	///
205	/// * `N` - The profiler counter ID (0-15 typically)
206	///
207	/// # Example
208	///
209	/// ```rust,ignore
210	/// use cuda_device::debug;
211	///
212	/// debug::prof_trigger::<0>();  // Mark start of region
213	/// // ... computation ...
214	/// debug::prof_trigger::<1>();  // Mark end of region
215	/// ```
216	///
217	/// # Notes
218	///
219	/// - Useful for marking regions of interest in profiler traces
220	/// - Counter IDs should be consistent across kernel invocations
221	/// - Has minimal overhead when not profiling
222	#[inline(never)]
223	pub fn prof_trigger<const N: u32>() {
224	    // Lowered to: inline PTX "pmevent N;"
225	    unreachable!("prof_trigger called outside CUDA kernel context")
226	}
