228	// =============================================================================
229	// Assertion Macro
230	// =============================================================================
231	
232	/// GPU-side assertion macro.
233	///
234	/// Checks a condition at runtime and aborts the kernel if it fails.
235	/// This is equivalent to `assert!()` but works on GPU kernels.
236	///
237	/// # Usage
238	///
239	/// ```rust,ignore
240	/// use cuda_device::gpu_assert;
241	///
242	/// // Simple assertion
243	/// gpu_assert!(x >= 0);
244	///
245	/// // With custom message (message is ignored in current impl)
246	/// gpu_assert!(idx < len, "Index out of bounds");
247	/// ```
248	///
249	/// # Behavior
250	///
251	/// When the condition is false:
252	/// - The kernel execution is aborted via `trap()`
253	/// - The CUDA driver reports an error to the host
254	/// - Other threads may continue briefly before the error propagates
255	///
256	/// # Notes
257	///
258	/// - Use sparingly in performance-critical code
259	/// - The message argument is currently ignored (will be supported with assertfail)
260	/// - For debugging, consider using [`breakpoint()`] instead
261	#[macro_export]
262	macro_rules! gpu_assert {
263	    ($cond:expr) => {
264	        if !$cond {
265	            $crate::debug::trap();
266	        }
267	    };
268	    ($cond:expr, $msg:expr) => {
269	        if !$cond {
270	            // TODO (npasham): Use llvm.nvvm.assertfail for better error messages with file/line
271	            $crate::debug::trap();
272	        }
273	    };
274	}
