280	/// Internal vprintf wrapper for GPU printf support.
281	///
282	/// This function is recognized by the cuda-oxide compiler and replaced with
283	/// an actual `vprintf` call in the generated PTX. Do not call directly.
284	///
285	/// # Arguments
286	///
287	/// * `format` - Pointer to null-terminated C format string (in global memory)
288	/// * `args` - Pointer to packed argument buffer (following C vararg ABI)
289	///
290	/// # Returns
291	///
292	/// Number of arguments on success, negative value on error.
293	/// Note: Unlike standard C printf which returns character count, CUDA's vprintf
294	/// returns the argument count because the GPU only marshals args to a buffer -
295	/// the host does the actual formatting later.
296	///
297	/// # Safety
298	///
299	/// This function only works within CUDA kernel context. The compiler replaces
300	/// calls with actual vprintf instructions. Calling from host code will panic.
301	#[doc(hidden)]
302	#[inline(never)]
303	pub fn __gpu_vprintf(_format: *const u8, _args: *const u8) -> i32 {
304	    unreachable!("__gpu_vprintf called outside CUDA kernel context")
305	}
306	
307	/// Trait for GPU printf argument promotion.
308	///
309	/// Implements C vararg promotion rules:
310	/// - `i8`, `i16` → `i32`
311	/// - `u8`, `u16` → `u32`
312	/// - `f32` → `f64`
313	/// - `bool` → `i32`
314	/// - 64-bit types stay as-is
315	pub trait GpuPrintfArg {
316	    /// The promoted type for C vararg ABI
317	    type Promoted: Copy;
318	
319	    /// C format specifier character for this type
320	    const FORMAT_CHAR: char;
321	
322	    /// Whether this is a 64-bit type (needs `ll` modifier)
323	    const IS_64BIT: bool;
324	
325	    /// Whether this is a floating point type
326	    const IS_FLOAT: bool;
327	
328	    /// Promote the value to the vararg type
329	    fn promote(self) -> Self::Promoted;
330	}
331	
